%[text] # 例8.7（ウェーブレット縮退処理）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2026a
%[text] ## 準備
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example08_07"; % mfilename

imgname = "msipimg08";
imgfmt = "tiff";

close all
%%
%[text] ## 画像データの読込
imgfile = fullfile(datfolder,imgname);
X = imresize(im2double(rgb2gray(imread(imgfile,imgfmt))),[96 96],'bilinear');

figure(1) %[output:83a5851b]
subplot(1,3,1) %[output:83a5851b]
imshow(X) %[output:83a5851b]
title('原画像') %[output:83a5851b]
%%
%[text] ## 分析処理
%[text] 直交ウェーブレット変換
nlevels = 3;

% Preparation of filters for wavelets
iswtb = license('checkout','wavelet_toolbox');
if iswtb % Functions in Wavelet Toolbox are used %[output:group:47ae9ad4]
    dwtmode('per') %[output:68abf722]
    wname = "haar"; %[control:dropdown:5881]{"position":[13,19]}
    [h0,h1,f0,f1] = wfilters(wname) %[output:9021bd3e] %[output:594c30b2] %[output:6df091ba] %[output:5cbd22f7]
else
    import msip.ezwavedec2
    import msip.ezwaverec2
    h0 = [1 1]/sqrt(2);
    h1 = [-1 1]/sqrt(2);
    f0 = [1 1]/sqrt(2);
    f1 = [1 -1]/sqrt(2);
    clear H  F
    % Analysis bi-variate filters
    H.h00 = h0(:)*h0(:).';
    H.h01 = h0(:)*h1(:).';
    H.h10 = h1(:)*h0(:).';
    H.h11 = h1(:)*h1(:).';
    % Synthesis bi-variate filters
    F.f00 = f0(:)*f0(:).';
    F.f01 = f0(:)*f1(:).';
    F.f10 = f1(:)*f0(:).';
    F.f11 = f1(:)*f1(:).';
end %[output:group:47ae9ad4]
%%
%[text] ### 観測画像
sigmaw = 20/255;
rng(0)
V = imnoise(X,'gaussian',0,sigmaw^2);
figure(1)
subplot(1,3,2) %[output:593dbe19]
imshow(V) %[output:593dbe19]
title("観測画像 PSNR: "+num2str(psnr(X,V))+" dB") %[output:593dbe19]
imwrite(V,fullfile(resfolder,"fig08-05a.png"))
%%
%[text] ### 分析処理 (Analysis process)
if iswtb
    [coefs,scales] = wavedec2(V,nlevels,h0,h1);
    % Reconstruction to check PR
    Y = waverec2(coefs,scales,f0,f1);
else
    [coefs,scales] = ezwavedec2(V,nlevels,H);
    % Reconstruction to check PR%
    Y = ezwaverec2(coefs,scales,F);
end
assert(norm(V-Y,"fro")^2/numel(V)<1e-18,'Perfect reconstruction is violated.')
%%
%[text] ### 変換係数の配列化 (Alignment of coefficients)
C = aligncoefs(coefs,scales);
figure(2) %[output:3fe81228]
imshow(abs(C)) %[output:3fe81228]
imwrite(C,fullfile(resfolder,"fig08-05b.png"))
%%
%[text] ### ウェーブレット縮退処理
lambda = 0.073;
if iswtb
    [coefs,scales] = wavedec2(V,nlevels,h0,h1);
    coefs = softthresh(coefs,lambda);
    Y = waverec2(coefs,scales,f0,f1);
else
    [coefs,scales] = ezwavedec2(V,nlevels,H);
    coefs = softthresh(coefs,lambda);
    Y = ezwaverec2(coefs,scales,F);
end
figure(1)
subplot(1,3,3) %[output:104830e7]
imshow(Y) %[output:104830e7]
title("ノイズ除去画像 PSNR: "+num2str(psnr(X,Y))+" dB") %[output:104830e7]
imwrite(Y,fullfile(resfolder,"fig08-05c.png"))
%%
%[text] ### 関数定義
%[text] ソフト閾値処理
function y = softthresh(x,lambda)
    y = x + abs(x-lambda)/2 - abs(x+lambda)/2;
end
%[text] 変換係数の配列化 (Alignment of coefficients)
function c00 = aligncoefs(coefs,scales)
nlevels = size(scales,1)-2;
pos = 0;
dim = scales(1,:);
nel = prod(dim);
c00 = reshape(coefs(pos+1:pos+nel),dim)/(2^nlevels);
pos = nel;
for ilv = 1:nlevels
    dim = scales(ilv+1,:);
    nel = prod(dim);
    %
    c10 = abs(reshape(coefs(pos+1:pos+nel),dim));%+.5;
    pos = pos + nel;
    %
    c01 = abs(reshape(coefs(pos+1:pos+nel),dim)); %+.5;
    pos = pos + nel;
    %
    c11 = abs(reshape(coefs(pos+1:pos+nel),dim)); %+.5;
    pos = pos + nel;
    %
    c00 = [ c00 c01; c10 c11 ];
end
end
